function normalize(str) {
    if (!str) return "";
    return String(str)
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "") // Remove acentos
        .replace(/[\s\W_]+/g, "")        // Remove todos os espaços e pontuação
        .toLowerCase();
}

const grupos = {};

payload.forEach(item => {
    // Campos de composição
    const incl = normalize(item["COMPOSICAO_INCLUI"] || item["Composicao_Inclui"]);
    const excl = normalize(item["COMPOSICAO_EXCLUI"] || item["Composicao_Exclui"]);
    const obs  = normalize(item["OBSERVACAO"] || item["Observacao"]);

    // Novos campos (incluídos no agrupamento)
    const rede   = normalize(item["REDE"] || item["Rede"]);
    const tabela = normalize(item["TABELA"] || item["Tabela"]);

    // Chave de agrupamento agora com REDE e TABELA também
    const chave = rede + '|' + tabela + '|' + incl + '|' + excl + '|' + obs;

    if (!grupos[chave]) grupos[chave] = [];
    grupos[chave].push(item);
});

